import anthropic
from dataclasses import dataclass, field
from typing import Optional

client = anthropic.Anthropic()

@dataclass
class ChainState:
    """Typed state object that travels through the chain."""
    original_input: str
    research_summary: Optional[str] = None
    draft_output: Optional[str] = None
    critique: Optional[str] = None
    final_output: Optional[str] = None
    errors: list = field(default_factory=list)
    current_step: str = "start"

def step_research(state: ChainState) -> ChainState:
    """Step 1: Research the topic."""
    state.current_step = "research"
    try:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=2048,
            messages=[{
                "role": "user",
                "content": f"Summarize key facts about: {state.original_input}\nBe factual and concise."
            }]
        )
        state.research_summary = response.content[0].text
    except Exception as e:
        state.errors.append(f"research step failed: {e}")
    return state

def step_draft(state: ChainState) -> ChainState:
    """Step 2: Draft using research."""
    if state.research_summary is None:
        state.errors.append("draft step skipped: no research summary")
        return state
    state.current_step = "draft"
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        messages=[{
            "role": "user",
            "content": (
                f"Write a clear explanation of '{state.original_input}' "
                f"using these research notes:\n{state.research_summary}"
            )
        }]
    )
    state.draft_output = response.content[0].text
    return state

def step_critique(state: ChainState) -> ChainState:
    """Step 3: Self-critique the draft."""
    if state.draft_output is None:
        return state
    state.current_step = "critique"
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        messages=[{
            "role": "user",
            "content": (
                f"Critique this explanation for accuracy and clarity. "
                f"List specific improvements needed:\n{state.draft_output}"
            )
        }]
    )
    state.critique = response.content[0].text
    return state

def step_revise(state: ChainState) -> ChainState:
    """Step 4: Revise based on critique."""
    if not (state.draft_output and state.critique):
        return state
    state.current_step = "revise"
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        messages=[{
            "role": "user",
            "content": (
                f"Revise this explanation applying the critique below.\n\n"
                f"Original:\n{state.draft_output}\n\n"
                f"Critique:\n{state.critique}\n\n"
                "Return only the revised explanation."
            )
        }]
    )
    state.final_output = response.content[0].text
    state.current_step = "done"
    return state

def run_chain(topic: str) -> ChainState:
    state = ChainState(original_input=topic)
    for step in [step_research, step_draft, step_critique, step_revise]:
        state = step(state)
        if state.errors:
            print(f"Chain stopped at {state.current_step} due to errors: {state.errors}")
            break
    return state
